import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FolderKanban, CheckCircle2, Clock, AlertTriangle, ArrowRight, Plus } from 'lucide-react';
import { projectsApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { formatRelativeTime, truncate, isOverdue } from '../utils/helpers';

export default function DashboardPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    projectsApi.list({ limit:12 })
      .then(({data}) => setProjects(data.data||[]))
      .catch(()=>{})
      .finally(()=>setLoading(false));
  }, []);

  const hour = new Date().getHours();
  const greeting = hour<12?'Good morning':hour<18?'Good afternoon':'Good evening';
  const active = projects.filter(p=>p.status==='ACTIVE').length;

  const stats = [
    { label:'Active Projects', value:active,          icon:<FolderKanban size={18}/>, color:'var(--primary)',  bg:'var(--primary-bg)' },
    { label:'Total Projects',  value:projects.length, icon:<CheckCircle2 size={18}/>, color:'var(--green)',    bg:'var(--green-bg)' },
    { label:'Tasks Due Today', value:'—',             icon:<Clock size={18}/>,        color:'var(--yellow)',   bg:'var(--yellow-bg)' },
    { label:'Overdue',         value:'—',             icon:<AlertTriangle size={18}/>,color:'var(--red)',      bg:'var(--red-bg)' },
  ];

  return (
    <div>
      {/* Greeting */}
      <div style={{marginBottom:'1.75rem'}}>
        <h1 style={{fontSize:'1.5rem',fontWeight:800,letterSpacing:'-.02em',marginBottom:4}}>
          {greeting}, {user?.name?.split(' ')[0]} 👋
        </h1>
        <p style={{color:'var(--text-2)',fontSize:'.9rem'}}>Here's what's happening across your projects today.</p>
      </div>

      {/* Stats */}
      <div className="grid-4" style={{marginBottom:'2rem'}}>
        {stats.map(s => (
          <div className="stat-card" key={s.label}>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'.75rem'}}>
              <span className="stat-label">{s.label}</span>
              <div className="stat-icon" style={{background:s.bg,color:s.color}}>{s.icon}</div>
            </div>
            <div className="stat-value" style={{color:'var(--text)'}}>{loading?'—':s.value}</div>
          </div>
        ))}
      </div>

      {/* Projects header */}
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:'1rem'}}>
        <h2 style={{fontSize:'1rem',fontWeight:700,letterSpacing:'-.01em'}}>Recent Projects</h2>
        <button className="btn btn-primary btn-sm" onClick={()=>navigate('/projects')}>
          <Plus size={14}/> New Project
        </button>
      </div>

      {loading ? (
        <div className="spinner-center"><div className="spinner spinner-lg"/></div>
      ) : projects.length===0 ? (
        <div className="empty-state">
          <FolderKanban size={48}/>
          <h3>No projects yet</h3>
          <p>Create your first project to start collaborating</p>
          <button className="btn btn-primary" onClick={()=>navigate('/projects')}><Plus size={14}/> Create Project</button>
        </div>
      ) : (
        <div className="grid-3">
          {projects.map(p => (
            <div key={p._id} className="card card-hover" onClick={()=>navigate(`/projects/${p._id}`)}>
              <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:'0.6rem'}}>
                <div style={{display:'flex',alignItems:'center',gap:7}}>
                  <span style={{fontFamily:'ui-monospace,monospace',fontSize:'.7rem',fontWeight:700,background:'var(--primary-bg)',color:'var(--primary-text)',padding:'2px 7px',borderRadius:5}}>
                    {p.key}
                  </span>
                  <span style={{fontSize:'.7rem',fontWeight:600,color:p.status==='ACTIVE'?'var(--green-text)':'var(--text-3)',textTransform:'uppercase',letterSpacing:'.04em'}}>
                    {p.status}
                  </span>
                </div>
                <ArrowRight size={14} style={{color:'var(--text-3)',flexShrink:0,marginTop:2}}/>
              </div>
              <h3 style={{fontSize:'.95rem',fontWeight:700,marginBottom:p.description?'.4rem':'.75rem',letterSpacing:'-.01em'}}>{p.name}</h3>
              {p.description && (
                <p className="text-2 text-sm" style={{marginBottom:'.75rem',lineHeight:1.5}}>
                  {truncate(p.description,80)}
                </p>
              )}
              <div style={{display:'flex',alignItems:'center',gap:7,marginTop:'auto'}}>
                <div className="avatar avatar-sm">{p.owner?.name?.[0]?.toUpperCase()}</div>
                <span className="text-xs text-3">{p.owner?.name} · {formatRelativeTime(p.createdAt)}</span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
